{"code":"import json
import re

with open(locals()['var_function-call-9863159268791541729'], 'r') as f:
    businesses = json.load(f)

state_pattern = re.compile(r" in [^,]+, ([A-Z]{2})")
state_total_reviews = {}

for b in businesses:
    desc = b.get('description', '')
    match = state_pattern.search(desc)
    if match:
        state = match.group(1)
        try:
            rc = int(b.get('review_count', 0))
        except:
            rc = 0

        if state not in state_total_reviews:
            state_total_reviews[state] = 0
        state_total_reviews[state] += rc

sorted_states = sorted(state_total_reviews.items(), key=lambda x: x[1], reverse=True)
print("__RESULT__:")
print(json.dumps(sorted_states))
